import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";
  const eventQuery = "2026 FIFA World Cup Winner";

  const result = await callMcpSkill({
    toolId,
    toolName: "analyze_event_whale_breakdown",
    args: {
      marketQuery: eventQuery,
      maxOutcomes: 20
    }
  });

  const wanted = ["Spain", "France", "England", "Switzerland", "New Zealand", "South Korea"];
  const rows = Array.isArray(result?.whalesByOutcome) ? result.whalesByOutcome : [];

  const sampled = rows.filter((row) => wanted.includes(row?.outcome));
  sampled.sort((a, b) => (b?.totalWhaleValue ?? 0) - (a?.totalWhaleValue ?? 0));

  const strongest = sampled[0] || null;

  return {
    eventTitle: result?.eventTitle || eventQuery,
    topWhaleOutcome: result?.topWhaleOutcome || null,
    sampledOutcomes: sampled.map((row) => ({
      rank: row.rank,
      outcome: row.outcome,
      whaleCount: row.whaleCount,
      totalWhaleValue: row.totalWhaleValue,
      currentPrice: row.currentPrice,
      convictionLevel: row.convictionLevel
    })),
    strongestAmongSampled: strongest
      ? {
          outcome: strongest.outcome,
          totalWhaleValue: strongest.totalWhaleValue,
          whaleCount: strongest.whaleCount,
          convictionLevel: strongest.convictionLevel
        }
      : null,
    selectionNote: strongest
      ? "Among the sampled outcomes you named, this one has the highest whale backing by total whale value."
      : "No matching sampled outcomes were returned in the whale breakdown."
  };
}

