  const marketQuery = "Will Paris Saint-Germain FC win on 2026-04-08?";

  const resolved = await callMcpSkill({
    toolId,
    toolName: "search_and_get_outcomes",
    args: {
      query: "Paris Saint-Germain",
      sortBy: "volume",
      category: "sports",
    },
  });

  const outcomes = Array.isArray(resolved?.outcomes) ? resolved.outcomes : [];

  const isPsgFootballMatch =
    typeof resolved?.eventTitle === "string" &&
    /paris saint-germain|psg/i.test(resolved.eventTitle) &&
    !/podcast|show|episode/i.test(resolved.eventTitle);

  const ranked = isPsgFootballMatch
    ? pickTopSemanticCandidates({
        target: marketQuery,
        candidates: outcomes,
        requiredTerms: ["Paris Saint-Germain", "PSG", "win"],
        avoidTerms: ["player", "score", "next goal", "to qualify"],
        limit: 1,
      })
    : [];

  const picked = Array.isArray(ranked) && ranked.length > 0 ? ranked[0] : null;

  if (!isPsgFootballMatch || !picked || (typeof picked.tokenId !== "string" && typeof picked.conditionId !== "string")) {
    return {
      missingData: ["tokenId"],
      attemptedBranches: ["search_and_get_outcomes(query)", "semantic_targeting_rank"],
      stopReason: "Could not deterministically identify the requested PSG market token from live outcomes.",
      resolvedMarket: resolved?.eventTitle || null,
      candidateCount: outcomes.length,
      fetchedAt: resolved?.fetchedAt || null,
    };
  }

  const params = await callMcpSkill({
    toolId,
    toolName: "get_market_parameters",
    args: {
      tokenId: picked.tokenId || undefined,
      conditionId: picked.conditionId || undefined,
    },
  });

  return {
    market: resolved?.eventTitle || null,
    selectedOutcome: picked.name || null,
    tokenId: picked.tokenId,
    tickSize: params?.tickSize ?? null,
    feeRateBps: params?.feeRateBps ?? null,
    minOrderSize: params?.minOrderSize ?? null,
    negRisk: params?.negRisk ?? null,
    fetchedAt: params?.fetchedAt || resolved?.fetchedAt || null,
  };
}

