  const highestVolume = liveBuckets.reduce((best, cur) => {
    if (!best) return cur;
    const bv = typeof best.volume === "number" ? best.volume : -1;
    const cv = typeof cur.volume === "number" ? cur.volume : -1;
    if (cv > bv) return cur;
    return best;
  }, null);

  return {
    event: result?.eventTitle ?? result?.eventUrl ?? "US x Iran ceasefire by...?",
    liveBuckets: liveBuckets.map((o) => ({
      name: o.name,
      price: o.price,
      volume: o.volume,
      conditionId: o.conditionId,
      tokenId: o.tokenId,
      parsedDate: o.parsedDate
    })),
    expiredBuckets: expiredBuckets.map((o) => ({
      name: o.name,
      price: o.price,
      volume: o.volume,
      conditionId: o.conditionId,
      tokenId: o.tokenId,
      parsedDate: o.parsedDate
    })),
    leadersAmongLiveBuckets: {
      highestQuotedProbability: highestProbability
        ? {
            name: highestProbability.name,
            price: highestProbability.price,
            volume: highestProbability.volume
          }
        : null,
      mostVolume: highestVolume
        ? {
            name: highestVolume.name,
            price: highestVolume.price,
            volume: highestVolume.volume
          }
        : null
    },
    selectionReason: result?.searchMethod ?? result?.matchConfidence ?? null
  };
}
